15	#![deny(warnings)]
16	#![allow(non_camel_case_types)]
17	#![allow(private_interfaces)]
18	
19	//! Dictionary refresh — downloads public domain name/city/word data,
20	//! transforms to the format consumed by apcrd_dictionaries.
21	//! Usage: cargo run --bin apcad
22	
23	// RCG output discipline: all emission via apcrl_*! — no direct println!/eprintln!
24	
25	use std::collections::{BTreeSet, HashMap};
26	use std::io::Read;
27	
28	// Output directory — baked at compile time from Cargo.toml location
29	const ZAPCAD_DICT_DIR: &str = concat!(env!("CARGO_MANIFEST_DIR"), "/dictionaries");
30	
31	// SSA staging path — user places manually downloaded zip here on 403
32	const ZAPCAD_SSA_STAGING: &str =
33	    concat!(env!("CARGO_MANIFEST_DIR"), "/dictionaries/.ssa_names_staging.zip");
34	
35	// Source URLs
36	const ZAPCAD_URL_SURNAMES:  &str =
37	    "https://www2.census.gov/topics/genealogy/2010surnames/names.zip";
38	const ZAPCAD_URL_SSA_NAMES: &str =
39	    "https://www.ssa.gov/oact/babynames/names.zip";
40	const ZAPCAD_URL_CITIES:    &str =
41	    "https://www2.census.gov/programs-surveys/popest/datasets/2020-2023/cities/totals/sub-est2023.csv";
42	const ZAPCAD_URL_ENGLISH:   &str =
43	    "https://norvig.com/ngrams/count_1w.txt";
44	
45	// Limits
46	const ZAPCAD_SURNAME_LIMIT:   usize = 1000;
47	const ZAPCAD_FIRSTNAME_LIMIT: usize = 1000;
48	const ZAPCAD_CITY_POP_LIMIT:  usize = 100;
49	const ZAPCAD_ENGLISH_LIMIT:   usize = 5000;
50	
51	// Municipal suffixes to strip (case-insensitive, trailing)
52	const ZAPCAD_CITY_SUFFIXES: &[&str] = &[
53	    " city", " town", " village", " borough", " municipality", " cdp",
54	];
55	
56	// 50 US state capitals
57	const ZAPCAD_STATE_CAPITALS: &[&str] = &[
58	    "albany", "annapolis", "atlanta", "augusta", "austin",
59	    "baton rouge", "bismarck", "boise", "boston", "carson city",
60	    "charleston", "cheyenne", "columbia", "columbus", "concord",
61	    "denver", "des moines", "dover", "frankfort", "harrisburg",
62	    "hartford", "helena", "honolulu", "indianapolis", "jackson",
63	    "jefferson city", "juneau", "lansing", "lincoln", "little rock",
64	    "madison", "montgomery", "montpelier", "nashville", "oklahoma city",
65	    "olympia", "phoenix", "pierre", "providence", "raleigh",
66	    "richmond", "sacramento", "salem", "salt lake city", "santa fe",
67	    "springfield", "st. paul", "tallahassee", "topeka", "trenton",
68	];
69	
70	// ---------------------------------------------------------------------------
71	// Main
72	// ---------------------------------------------------------------------------
73	
74	fn main() {
75	    apcd::apcrl_info_now!("dictionary refresh starting");
76	    apcd::apcrl_info_now!("output directory: {}", ZAPCAD_DICT_DIR);
77	
78	    let surnames = zapcad_fetch_surnames();
79	    zapcad_write_dict("surnames.txt", &surnames);
80	
81	    let firstnames = zapcad_fetch_firstnames();
82	    zapcad_write_dict("firstnames.txt", &firstnames);
83	
84	    let cities = zapcad_fetch_cities();
85	    zapcad_write_dict("cities.txt", &cities);
86	
87	    let english = zapcad_fetch_english();
88	    zapcad_write_dict("english_whitelist.txt", &english);
89	
90	    apcd::apcrl_info_now!("dictionary refresh complete — 4 files written");
91	}
92	
93	// ---------------------------------------------------------------------------
94	// Surnames — Census 2010 (top 1000)
95	// ---------------------------------------------------------------------------
96	
97	fn zapcad_fetch_surnames() -> Vec<String> {
98	    apcd::apcrl_info_now!("fetching surnames from Census 2010");
99	    let zip_bytes = zapcad_download_bytes(ZAPCAD_URL_SURNAMES);
100	    let csv_text = zapcad_extract_zip_entry(&zip_bytes, "Names_2010Census.csv");
101	
102	    let mut rdr = csv::ReaderBuilder::new()
103	        .has_headers(true)
104	        .from_reader(csv_text.as_bytes());
105	
106	    let headers = rdr.headers()
107	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("surnames CSV headers: {}", e))
108	        .clone();
109	    let name_idx = headers.iter().position(|h| h == "name")
110	        .unwrap_or_else(|| apcd::apcrl_fatal_now!("surnames CSV missing 'name' column"));
111	
112	    let mut names = Vec::new();
113	    for result in rdr.records() {
114	        if names.len() >= ZAPCAD_SURNAME_LIMIT { break; }
115	        let record = result
116	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("surnames CSV record: {}", e));
117	        let name = record.get(name_idx)
118	            .unwrap_or_else(|| apcd::apcrl_fatal_now!("surnames CSV missing name field"));
119	        names.push(name.to_lowercase());
120	    }
121	
122	    apcd::apcrl_info_now!("surnames: {} entries extracted", names.len());
123	    zapcad_sort_dedup(names)
124	}
125	
126	// ---------------------------------------------------------------------------
127	// First names — SSA Baby Names (top 1000 by aggregate frequency)
128	// ---------------------------------------------------------------------------
129	
130	fn zapcad_fetch_firstnames() -> Vec<String> {
131	    apcd::apcrl_info_now!("fetching first names from SSA Baby Names");
132	    let zip_bytes = zapcad_fetch_ssa_zip();
133	
134	    let cursor = std::io::Cursor::new(&zip_bytes);
135	    let mut archive = zip::ZipArchive::new(cursor)
136	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("SSA zip open: {}", e));
137	
138	    let mut counts: HashMap<String, u64> = HashMap::new();
139	    for i in 0..archive.len() {
140	        let mut file = archive.by_index(i)
141	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("SSA zip entry {}: {}", i, e));
142	        let fname = file.name().to_string();
143	        if !fname.starts_with("yob") || !fname.ends_with(".txt") { continue; }
144	
145	        let mut contents = String::new();
146	        file.read_to_string(&mut contents)
147	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("SSA read {}: {}", fname, e));
148	
149	        for line in contents.lines() {
150	            let parts: Vec<&str> = line.split(',').collect();
151	            if parts.len() < 3 { continue; }
152	            let name = parts[0].to_lowercase();
153	            let count: u64 = parts[2].parse().unwrap_or(0);
154	            *counts.entry(name).or_insert(0) += count;
155	        }
156	    }
157	
158	    let mut ranked: Vec<(String, u64)> = counts.into_iter().collect();
159	    ranked.sort_by(|a, b| b.1.cmp(&a.1));
160	    let names: Vec<String> = ranked.into_iter()
161	        .take(ZAPCAD_FIRSTNAME_LIMIT)
162	        .map(|(name, _)| name)
163	        .collect();
164	
165	    apcd::apcrl_info_now!("firstnames: {} entries extracted", names.len());
166	    zapcad_sort_dedup(names)
167	}
168	
169	fn zapcad_fetch_ssa_zip() -> Vec<u8> {
170	    match ureq::get(ZAPCAD_URL_SSA_NAMES).call() {
171	        Ok(resp) => {
172	            let mut bytes = Vec::new();
173	            resp.into_reader().read_to_end(&mut bytes)
174	                .unwrap_or_else(|e| apcd::apcrl_fatal_now!("SSA download read: {}", e));
175	            apcd::apcrl_info_now!("SSA download: {} bytes", bytes.len());
176	            bytes
177	        }
178	        Err(ureq::Error::Status(code, _)) => {
179	            apcd::apcrl_error_now!("SSA download returned HTTP {}", code);
180	            zapcad_load_ssa_staging()
181	        }
182	        Err(e) => {
183	            apcd::apcrl_error_now!("SSA download failed: {}", e);
184	            zapcad_load_ssa_staging()
185	        }
186	    }
187	}
188	
189	fn zapcad_load_ssa_staging() -> Vec<u8> {
190	    let path = std::path::Path::new(ZAPCAD_SSA_STAGING);
191	    if path.exists() {
192	        apcd::apcrl_info_now!("loading SSA data from staging: {}", ZAPCAD_SSA_STAGING);
193	        std::fs::read(path)
194	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("staging read: {}", e))
195	    } else {
196	        apcd::apcrl_fatal_now!(
197	            "SSA blocked download (Akamai bot protection).\n\
198	             Manual workaround:\n\
199	             1. Open in browser: {}\n\
200	             2. Save the downloaded file to: {}\n\
201	             3. Re-run this tool",
202	            ZAPCAD_URL_SSA_NAMES, ZAPCAD_SSA_STAGING
203	        );
204	    }
205	}
206	
207	// ---------------------------------------------------------------------------
208	// Cities — Census Population Estimates (top 100 by pop + 50 state capitals)
209	// ---------------------------------------------------------------------------
210	
211	fn zapcad_fetch_cities() -> Vec<String> {
212	    apcd::apcrl_info_now!("fetching cities from Census population estimates");
213	    let csv_text = zapcad_download_text(ZAPCAD_URL_CITIES);
214	
215	    let mut rdr = csv::ReaderBuilder::new()
216	        .has_headers(true)
217	        .from_reader(csv_text.as_bytes());
218	
219	    let headers = rdr.headers()
220	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("cities CSV headers: {}", e))
221	        .clone();
222	    let sumlev_idx = headers.iter().position(|h| h == "SUMLEV")
223	        .unwrap_or_else(|| apcd::apcrl_fatal_now!("cities CSV missing SUMLEV"));
224	    let name_idx = headers.iter().position(|h| h == "NAME")
225	        .unwrap_or_else(|| apcd::apcrl_fatal_now!("cities CSV missing NAME"));
226	    let pop_idx = headers.iter().position(|h| h == "POPESTIMATE2023")
227	        .unwrap_or_else(|| apcd::apcrl_fatal_now!("cities CSV missing POPESTIMATE2023"));
228	
229	    let mut places: Vec<(String, u64)> = Vec::new();
230	    for result in rdr.records() {
231	        let record = result
232	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("cities CSV record: {}", e));
233	        if record.get(sumlev_idx).unwrap_or("") != "162" { continue; }
234	        let raw_name = record.get(name_idx).unwrap_or("").to_string();
235	        let pop: u64 = record.get(pop_idx).unwrap_or("0").parse().unwrap_or(0);
236	        places.push((raw_name, pop));
237	    }
238	
239	    places.sort_by(|a, b| b.1.cmp(&a.1));
240	    let top_cities: Vec<String> = places.into_iter()
241	        .take(ZAPCAD_CITY_POP_LIMIT)
242	        .map(|(name, _)| zapcad_strip_city_suffix(&name))
243	        .collect();
244	
245	    let mut all: BTreeSet<String> = BTreeSet::new();
246	    for city in &top_cities {
247	        all.insert(city.clone());
248	    }
249	    for capital in ZAPCAD_STATE_CAPITALS {
250	        all.insert(capital.to_string());
251	    }
252	
253	    let result: Vec<String> = all.into_iter().collect();
254	    apcd::apcrl_info_now!("cities: {} entries", result.len());
255	    result
256	}
257	
258	fn zapcad_strip_city_suffix(name: &str) -> String {
259	    let trimmed = name.trim_matches('"').trim();
260	    let lower = trimmed.to_lowercase();
261	    for suffix in ZAPCAD_CITY_SUFFIXES {
262	        if let Some(stripped) = lower.strip_suffix(suffix) {
263	            return stripped.trim().to_string();
264	        }
265	    }
266	    lower
267	}
268	
269	// ---------------------------------------------------------------------------
270	// English whitelist — Norvig/Google (top 5000)
271	// ---------------------------------------------------------------------------
272	
273	fn zapcad_fetch_english() -> Vec<String> {
274	    apcd::apcrl_info_now!("fetching English whitelist from Norvig/Google n-grams");
275	    let text = zapcad_download_text(ZAPCAD_URL_ENGLISH);
276	
277	    let mut words = Vec::new();
278	    for line in text.lines() {
279	        if words.len() >= ZAPCAD_ENGLISH_LIMIT { break; }
280	        let parts: Vec<&str> = line.split('\t').collect();
281	        if parts.is_empty() { continue; }
282	        let word = parts[0].to_lowercase();
283	        if word.chars().any(|c| c.is_ascii_digit()) { continue; }
284	        if word.len() < 2 { continue; }
285	        words.push(word);
286	    }
287	
288	    apcd::apcrl_info_now!("english whitelist: {} entries extracted", words.len());
289	    zapcad_sort_dedup(words)
290	}
291	
292	// ---------------------------------------------------------------------------
293	// Shared helpers
294	// ---------------------------------------------------------------------------
295	
296	fn zapcad_download_bytes(url: &str) -> Vec<u8> {
297	    apcd::apcrl_info_now!("downloading: {}", url);
298	    let resp = ureq::get(url).call()
299	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("download failed {}: {}", url, e));
300	    let mut bytes = Vec::new();
301	    resp.into_reader().read_to_end(&mut bytes)
302	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("download read {}: {}", url, e));
303	    apcd::apcrl_info_now!("downloaded {} bytes from {}", bytes.len(), url);
304	    bytes
305	}
306	
307	fn zapcad_download_text(url: &str) -> String {
308	    apcd::apcrl_info_now!("downloading: {}", url);
309	    let resp = ureq::get(url).call()
310	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("download failed {}: {}", url, e));
311	    let text = resp.into_string()
312	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("download text {}: {}", url, e));
313	    apcd::apcrl_info_now!("downloaded {} bytes from {}", text.len(), url);
314	    text
315	}
316	
317	fn zapcad_extract_zip_entry(zip_bytes: &[u8], entry_name: &str) -> String {
318	    let cursor = std::io::Cursor::new(zip_bytes);
319	    let mut archive = zip::ZipArchive::new(cursor)
320	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("zip open: {}", e));
321	    let mut file = archive.by_name(entry_name)
322	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("zip entry '{}': {}", entry_name, e));
323	    let mut contents = String::new();
324	    file.read_to_string(&mut contents)
325	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("zip read '{}': {}", entry_name, e));
326	    contents
327	}
328	
329	fn zapcad_sort_dedup(mut items: Vec<String>) -> Vec<String> {
330	    items.sort();
331	    items.dedup();
332	    items
333	}
334	
335	fn zapcad_write_dict(filename: &str, entries: &[String]) {
336	    let path = std::path::Path::new(ZAPCAD_DICT_DIR).join(filename);
337	    let content = entries.join("\n") + "\n";
338	    std::fs::write(&path, &content)
339	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("write {}: {}", path.display(), e));
340	    apcd::apcrl_info_now!("wrote {} ({} entries, {} bytes)", filename, entries.len(), content.len());
341	}
342

