23	// ---------------------------------------------------------------------------
24	// Public types
25	// ---------------------------------------------------------------------------
26	
27	pub enum apcre_Result {
28	    Clinical {
29	        findings:   Vec<apcrm_Finding>,
30	        plain_text: String,
31	    },
32	    NonClinical {
33	        content_length: usize,
34	        content_type:   String,
35	        preview:        String,
36	    },
37	}
38	
39	// ---------------------------------------------------------------------------
40	// Constants
41	// ---------------------------------------------------------------------------
42	
43	const ZAPCRE_CLINICAL_LABELS: &[&str] = &[
44	    "patient:",
45	    "dob:",
46	    "mrn:",
47	    "attending:",
48	    "facility:",
49	    "chief complaint:",
50	    "history of present illness:",
51	    "assessment/plan:",
52	    "vitals:",
53	    "laboratory results:",
54	    "medications:",
55	    "allergies:",
56	    "physical exam:",
57	    "review of systems:",
58	];
59	
60	const ZAPCRE_CLINICAL_THRESHOLD: usize = 2;
61	
62	// ---------------------------------------------------------------------------
63	// Public API
64	// ---------------------------------------------------------------------------
65	
66	pub fn apcre_analyze(html: &str, dicts: &apcrd_Dictionaries) -> apcre_Result {
67	    let today = chrono::Local::now().date_naive();
68	    zapcre_analyze_with_date(html, dicts, today)
69	}
70	
71	pub(crate) fn zapcre_analyze_with_date(
72	    html: &str,
73	    dicts: &apcrd_Dictionaries,
74	    today: NaiveDate,
75	) -> apcre_Result {
76	    let doc = apcrp_parse::apcrp_parse(html);
77	
78	    if !zapcre_is_clinical(&doc.plain_text) {
79	        return apcre_Result::NonClinical {
80	            content_length: html.len(),
81	            content_type:   if html.contains('<') { "HTML".to_string() } else { "plain text".to_string() },
82	            preview:        html.chars().take(100).collect(),
83	        };
84	    }
85	
86	    let mut findings = Vec::new();
87	    findings.extend(apcrm_scan_regex(&doc.plain_text));
88	    findings.extend(apcrm_scan_anchored(&doc.spans));
89	    findings.extend(apcrm_scan_dictionary(&doc.plain_text, dicts));
90	
91	    zapcre_transform_dob(&mut findings, &doc, today);
92	
93	    findings = zapcre_merge_findings(findings);
94	    findings.sort_by_key(|f| f.offset);
95	
96	    apcre_Result::Clinical {
97	        findings,
98	        plain_text: doc.plain_text,
99	    }
100	}
101	
102	// ---------------------------------------------------------------------------
103	// Internal — clinical content heuristic
104	// ---------------------------------------------------------------------------
105	
106	fn zapcre_is_clinical(plain_text: &str) -> bool {
107	    let lower = plain_text.to_lowercase();
108	    let count = ZAPCRE_CLINICAL_LABELS
109	        .iter()
110	        .filter(|label| lower.contains(**label))
111	        .count();
112	    count >= ZAPCRE_CLINICAL_THRESHOLD
113	}
114	
115	// ---------------------------------------------------------------------------
116	// Internal — DOB → age transform
117	// ---------------------------------------------------------------------------
118	
119	fn zapcre_transform_dob(
120	    findings: &mut [apcrm_Finding],
121	    doc: &apcrp_parse::apcrp_Document,
122	    today: NaiveDate,
123	) {
124	    let dob_span = doc.spans.iter().find(|s| {
125	        s.kind == apcrp_parse::apcrp_SpanKind::LabeledField
126	            && s.label.as_deref() == Some("DOB")
127	    });
128	
129	    let dob_span = match dob_span {
130	        Some(s) => s,
131	        None    => return,
132	    };
133	
134	    let dob_date = match zapcre_parse_date(&dob_span.text) {
135	        Some(d) => d,
136	        None    => return,
137	    };
138	
139	    let age = zapcre_compute_age(dob_date, today);
140	    let age_str = if age > 89 {
141	        "Age: 90+".to_string()
142	    } else {
143	        format!("Age: {}", age)
144	    };
145	
146	    let value_offset = dob_span.offset + "DOB".len() + 2;
147	    let value_end    = value_offset + dob_span.text.len();
148	
149	    for finding in findings.iter_mut() {
150	        if finding.category == apcrm_PhiCategory::Date
151	            && finding.offset >= value_offset
152	            && finding.offset + finding.length <= value_end
153	        {
154	            finding.category    = apcrm_PhiCategory::Dob;
155	            finding.replacement = age_str.clone();
156	        }
157	    }
158	}
159	
160	fn zapcre_parse_date(text: &str) -> Option<NaiveDate> {
161	    NaiveDate::parse_from_str(text.trim(), "%m/%d/%Y")
162	        .or_else(|_| NaiveDate::parse_from_str(text.trim(), "%m-%d-%Y"))
163	        .or_else(|_| NaiveDate::parse_from_str(text.trim(), "%m/%d/%y"))
164	        .ok()
165	}
166	
167	pub(crate) fn zapcre_compute_age(dob: NaiveDate, today: NaiveDate) -> u32 {
168	    let mut age = today.year() - dob.year();
169	    if today.month() < dob.month()
170	        || (today.month() == dob.month() && today.day() < dob.day())
171	    {
172	        age -= 1;
173	    }
174	    age.max(0) as u32
175	}
176	
177	// ---------------------------------------------------------------------------
178	// Internal — merge findings by highest severity at each position
179	// ---------------------------------------------------------------------------
180	
181	fn zapcre_merge_findings(findings: Vec<apcrm_Finding>) -> Vec<apcrm_Finding> {
182	    let mut by_position: HashMap<(usize, usize), apcrm_Finding> = HashMap::new();
183	
184	    for finding in findings {
185	        let key = (finding.offset, finding.length);
186	        match by_position.get(&key) {
187	            Some(existing)
188	                if apcrm_severity_rank(existing.severity)
189	                    >= apcrm_severity_rank(finding.severity) =>
190	            {
191	                // existing has equal or higher severity — keep it
192	            }
193	            _ => {
194	                by_position.insert(key, finding);
195	            }
196	        }
197	    }
198	
199	    by_position.into_values().collect()
200	}
201	
202	// ---------------------------------------------------------------------------
203	// Anonymize — produce clean text from classified findings + toggle states
204	// ---------------------------------------------------------------------------
205	
206	pub fn apcre_anonymize(
207	    plain_text: &str,
208	    findings:   &[apcrm_Finding],
209	    toggle_states: &[String],
210	) -> String {
211	    let mut indexed: Vec<(usize, &apcrm_Finding)> = findings.iter().enumerate().collect();
212	    indexed.sort_by_key(|(_, f)| (f.offset, std::cmp::Reverse(f.length)));
213	
214	    let mut result = String::with_capacity(plain_text.len());
215	    let mut pos = 0;
216	
217	    for (idx, finding) in &indexed {
218	        if finding.offset < pos {
219	            continue;
220	        }
221	
222	        if finding.offset > pos {
223	            result.push_str(&plain_text[pos..finding.offset]);
224	        }
225	
226	        let state = toggle_states.get(*idx).map(|s| s.as_str()).unwrap_or("elide");
227	        if state == "pass" {
228	            result.push_str(&plain_text[finding.offset..finding.offset + finding.length]);
229	        } else {
230	            result.push_str(&finding.replacement);
231	        }
232	
233	        pos = finding.offset + finding.length;
234	    }
235	
236	    if pos < plain_text.len() {
237	        result.push_str(&plain_text[pos..]);
238	    }
239	
240	    result
241	}
